class Solution {
    public int shipWithinDays(int[] weights, int days) {
        int low = 0, high = 0;
        for (int w : weights) {
            low = Math.max(low, w);
            high += w;
        }
        while (low < high) {
            int mid = (low + high) / 2;
            if (canShip(weights, mid, days)) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }

    private boolean canShip(int[] weights, int capacity, int days) {
        int currentCapacity = 0;
        int daysNeeded = 1;
        for (int w : weights) {
            if (currentCapacity + w > capacity) {
                daysNeeded++;
                currentCapacity = 0;
            }
            currentCapacity += w;
        }
        return daysNeeded <= days;
    }
}

